import sys
input = sys.stdin.readline

def solve():
    n, m, q = map(int, input().split())
    grid = [[True]*m for _ in range(n)]

    R = [[0]*m for _ in range(n)]
    D = [[0]*m for _ in range(n)]

    def recompute():
        for i in range(n-1, -1, -1):
            for j in range(m-1, -1, -1):
                if not grid[i][j]:
                    R[i][j] = 0
                    D[i][j] = 0
                else:
                    # R[i][j]: start right
                    if j+1 < m and grid[i][j+1]:
                        R[i][j] = 1 + D[i][j+1]
                    else:
                        R[i][j] = 1
                    # D[i][j]: start down
                    if i+1 < n and grid[i+1][j]:
                        D[i][j] = 1 + R[i+1][j]
                    else:
                        D[i][j] = 1

    recompute()

    def total():
        s = 0
        for i in range(n):
            for j in range(m):
                if grid[i][j]:
                    # R[i][j] counts staircases starting right (including single cell)
                    # D[i][j] counts staircases starting down (including single cell)
                    # single cell counted twice, subtract once
                    s += R[i][j] + D[i][j] - 1
        return s

    out = []
    for _ in range(q):
        x, y = map(int, input().split())
        x -= 1; y -= 1
        grid[x][y] = not grid[x][y]
        recompute()
        out.append(total())

    print('\n'.join(map(str, out)))

solve()

